#include<stdio.h>
int main()
{
int n,x,v;
scanf("%d",&v);
n=v;
x=n-1;
while((x<n)&&(x>0))
{
if((n%x)!=0)
{
n=n-x;
}
x--;
}

printf("%d",n);
return 0;
}

